import{_ as s,C as r,o,c as d,a4 as i,E as a}from"./chunks/framework.CyI4nVbD.js";const g=JSON.parse('{"title":"The structure model","description":"","frontmatter":{},"headers":[],"relativePath":"general/structure-model.md","filePath":"general/structure-model.md"}'),n={name:"general/structure-model.md"};function l(h,e,c,p,u,m){const t=r("CifDemo");return o(),d("div",null,[e[0]||(e[0]=i(`<h1 id="the-structure-model" tabindex="-1">The structure model <a class="header-anchor" href="#the-structure-model" aria-label="Permalink to &quot;The structure model&quot;">​</a></h1><p><code>CrystalStructure</code> is the crystallographic domain model at the heart of CifVis: unit cell, atoms (with isotropic or anisotropic displacement parameters), bonds, hydrogen bonds, and symmetry. It is built directly from a parsed CIF block:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { CIF, CrystalStructure } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;cifvis&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> structure</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CrystalStructure.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fromCIF</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CIF</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cifText).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getBlock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span></code></pre></div><p>The structure model knows nothing about rendering — it is DOM- and Three.js-free, so it works in Node just as well as in the browser (import from <code>cifvis/nobrowser</code> in environments without a <code>window</code>).</p><h2 id="filters-how-the-displayed-structure-is-derived" tabindex="-1">Filters: how the displayed structure is derived <a class="header-anchor" href="#filters-how-the-displayed-structure-is-derived" aria-label="Permalink to &quot;Filters: how the displayed structure is derived&quot;">​</a></h2><p>What you <em>see</em> in a viewer is rarely the raw asymmetric unit from the CIF. Every time the displayed structure needs to change, <code>CrystalViewer</code> runs the base structure through six <strong>Filters</strong> (structure modifiers) in a fixed order, each one&#39;s output feeding the next:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>removeatoms → addhydrogen → missingbonds → disorder → symmetry → hydrogen</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Filter</th><th>Class</th><th>Purpose</th></tr></thead><tbody><tr><td><code>removeatoms</code></td><td><code>AtomLabelFilter</code></td><td>Strips explicitly excluded atoms.</td></tr><tr><td><code>addhydrogen</code></td><td><code>IsolatedHydrogenFixer</code></td><td>Bonds orphan hydrogen atoms to a nearby heavy atom.</td></tr><tr><td><code>missingbonds</code></td><td><code>BondGenerator</code></td><td>Generates bonds from interatomic distances when the CIF doesn&#39;t list them.</td></tr><tr><td><code>disorder</code></td><td><code>DisorderFilter</code></td><td>Shows only one disorder group (plus non-disordered atoms) at a time.</td></tr><tr><td><code>symmetry</code></td><td><code>SymmetryGrower</code></td><td>Grows one additional symmetry sphere via bonds, H-bonds, or the whole unit cell.</td></tr><tr><td><code>hydrogen</code></td><td><code>HydrogenFilter</code></td><td>Controls hydrogen display (hidden, constant-radius sphere, or real ADP).</td></tr></tbody></table><p>Each filter is a pure <code>CrystalStructure → CrystalStructure</code> transformation, so the same classes work with a viewer, with the widget&#39;s attributes, or completely standalone in batch tooling — see <a href="./../library/filters.html">Library → Filters</a> for modes and standalone use, and the widget&#39;s <a href="./../widget/attributes-reference.html"><code>hydrogen-mode</code> / <code>disorder-mode</code> / <code>symmetry-mode</code> attributes</a> for the declarative form.</p><h2 id="the-three-display-concepts" tabindex="-1">The three display concepts <a class="header-anchor" href="#the-three-display-concepts" aria-label="Permalink to &quot;The three display concepts&quot;">​</a></h2><p>Three of the filters correspond to the display modes you will meet throughout CifVis:</p><ul><li><strong>Hydrogen display</strong> — hydrogens can be hidden (<code>none</code>), drawn as small constant-radius spheres (<code>constant</code>), or drawn with their real refined displacement ellipsoids (<code>anisotropic</code>).</li><li><strong>Disorder groups</strong> — structures with disorder carry <code>disorder_group</code> assignments in the CIF. CifVis shows all groups at once (<code>all</code>) or one group at a time (<code>group1of2</code>, <code>group2of2</code>, … — named by rank and total count, not by the raw CIF group number).</li><li><strong>Symmetry growing</strong> — the asymmetric unit can be expanded by one symmetry sphere, following bonds (<code>fragment</code>), hydrogen bonds (<code>hbonds</code>), both (<code>fragment-hbonds</code>), or by displaying the whole unit cell (<code>cell</code>, <code>fragment-cell</code>).</li></ul><p>If a requested mode is not applicable to a structure (say, a disorder group mode on an ordered structure), viewer and widget fall back to an applicable mode automatically.</p>`,13)),a(t,{src:"/cif/urea.cif",caption:"Urea with hydrogens shown and the fragment grown through symmetry.","hydrogen-mode":"constant","symmetry-mode":"fragment",style:{"aspect-ratio":"16 / 9"}})])}const k=s(n,[["render",l]]);export{g as __pageData,k as default};
